SELECT username, email, role_id
FROM user_accounts
WHERE account_id >= 0;

SELECT semester_name
FROM semesters
WHERE semester_id = 0;

SELECT student_id, COUNT(submission_id) AS submission_count
FROM assignment_submissions
GROUP BY student_id;

SELECT course_offering_id, AVG(attendance) AS average_attendance
FROM student_enrollments
GROUP BY course_offering_id;
